// Java Memory Model guarantee with happens-before
public class HappensBefore {
    private static boolean ready = false;
    private static int answer = 0;

    public static void main(String[] args) throws InterruptedException {
        Thread writer = new Thread(() -> {
            answer = 42;                    // action A
            ready = true;                   // action B (volatile write)
        });

        Thread reader = new Thread(() -> {
            while (!ready) {                // action C (volatile read)
                Thread.yield();
            }
            System.out.println(answer);     // action D: guaranteed to see 42
        });

        writer.start();
        reader.start();
        writer.join();
        reader.join();
    }
    // B happens-before C (volatile), so A happens-before C
    // Therefore A happens-before D
}

// wait() — tied to object's monitor
class WaitExample {
    private boolean condition = false;

    public synchronized void awaitCondition() throws InterruptedException {
        while (!condition) {
            wait();  // releases lock, waits for notify
        }
    }

    public synchronized void triggerCondition() {
        condition = true;
        notifyAll();  // wake all waiters on this object
    }
}

// park() — no lock required
class ParkExample {
    private Thread waiter;
    private boolean ready = false;

    public void waitForSignal() {
        waiter = Thread.currentThread();
        while (!ready) {
            LockSupport.park();  // doesn't require lock
        }
    }

    public void signal() {
        ready = true;
        if (waiter != null) {
            LockSupport.unpark(waiter);  // explicit unpark
        }
    }
}

// Condition — modern replacement for wait/notify
class ConditionExample {
    private final Lock lock = new ReentrantLock();
    private final Condition condition = lock.newCondition();
    private boolean ready = false;

    public void awaitReady() throws InterruptedException {
        lock.lock();
        try {
            while (!ready) {
                condition.await();  // like wait() but with explicit lock
            }
        } finally {
            lock.unlock();
        }
    }

    public void markReady() {
        lock.lock();
        try {
            ready = true;
            condition.signalAll();
        } finally {
            lock.unlock();
        }
    }
}

// CAS via AtomicInteger
class CASExample {
    private AtomicInteger count = new AtomicInteger(0);

    public void incrementIfEven() {
        int current;
        do {
            current = count.get();
            if (current % 2 != 0) return;  // not even, abort
        } while (!count.compareAndSet(current, current + 1));
        // compareAndSet returns false if value changed, loop retries
    }
}

// Lock-free counter with CAS
class LockFreeCounter {
    private AtomicLong value = new AtomicLong(0);

    public void increment() {
        long current;
        do {
            current = value.get();
        } while (!value.compareAndSet(current, current + 1));
    }
}

// ABA problem: CAS doesn't detect value changed A->B->A
class ABAProblem {
    private AtomicReference<Node> head;

    public void push(Node node) {
        Node current;
        do {
            current = head.get();  // read A
            node.next = current;
        } while (!head.compareAndSet(current, node));
        // If current changed A->B->A, CAS still succeeds (false positive)
    }
    // Solution: use AtomicStampedReference or AtomicMarkableReference
}

// Atomic vs explicit lock performance
class PerformanceComparison {
    // Lock-free (better under low contention)
    static class AtomicCounter {
        AtomicLong count = new AtomicLong();
        void increment() {
            long current;
            do {
                current = count.get();
            } while (!count.compareAndSet(current, current + 1));
        }
    }

    // Lock-based (better under high contention)
    static class SyncCounter {
        long count;
        synchronized void increment() { count++; }
    }
}

