// ReentrantLock — flexible
class ReentrantLockExample {
    private final Lock lock = new ReentrantLock(true);  // fair
    private int count = 0;

    public void increment() throws InterruptedException {
        if (lock.tryLock(1, TimeUnit.SECONDS)) {  // try-lock
            try {
                count++;
            } finally {
                lock.unlock();  // explicit unlock (must be in finally)
            }
        } else {
            System.out.println("Timeout, could not acquire lock");
        }
    }

    public void incrementInterruptibly() throws InterruptedException {
        lock.lockInterruptibly();  // interruptible
        try {
            count++;
        } finally {
            lock.unlock();
        }
    }
}

// Condition for wait/notify replacement
class ProducerConsumer {
    private final Lock lock = new ReentrantLock();
    private final Condition notEmpty = lock.newCondition();
    private final Condition notFull = lock.newCondition();
    private final int[] buffer = new int[10];
    private int count = 0;

    public void put(int item) throws InterruptedException {
        lock.lock();
        try {
            while (count == buffer.length) {
                notFull.await();  // explicit condition
            }
            buffer[count++] = item;
            notEmpty.signalAll();
        } finally {
            lock.unlock();
        }
    }

    public int take() throws InterruptedException {
        lock.lock();
        try {
            while (count == 0) {
                notEmpty.await();
            }
            int result = buffer[--count];
            notFull.signalAll();
            return result;
        } finally {
            lock.unlock();
        }
    }
}

