// Service with retry logic
@Service
public class TransferService {
    @Autowired private AccountRepository repo;

    @Transactional
    public void transfer(Long fromId, Long toId, BigDecimal amount) {
        int retries = 3;
        while (retries > 0) {
            try {
                Account from = repo.findById(fromId).orElseThrow();
                Account to = repo.findById(toId).orElseThrow();

                from.setBalance(from.getBalance().subtract(amount));
                to.setBalance(to.getBalance().add(amount));

                repo.save(from);
                repo.save(to);
                return;
            } catch (OptimisticLockingFailureException ex) {
                retries--;
                if (retries == 0) throw ex;
                // Retry with fresh data
            }
        }
    }
}

// PESSIMISTIC LOCKING — using SELECT FOR UPDATE
@Repository
public interface AccountRepository extends JpaRepository<Account, Long> {
    @Lock(LockModeType.PESSIMISTIC_WRITE)
    @Query("select a from Account a where a.id = :id")
    Optional<Account> findByIdForUpdate(@Param("id") Long id);
}

// Service: no retry needed, lock is held until transaction ends
@Service
public class SafeTransferService {
    @Autowired private AccountRepository repo;

    @Transactional
    public void transfer(Long fromId, Long toId, BigDecimal amount) {
        // SELECT FOR UPDATE locks the rows
        Account from = repo.findByIdForUpdate(fromId).orElseThrow();
        Account to = repo.findByIdForUpdate(toId).orElseThrow();

        from.setBalance(from.getBalance().subtract(amount));
        to.setBalance(to.getBalance().add(amount));
        // No exception possible, lock released at transaction end
    }
}

