// Complete lifecycle demonstration
@Component
public class LifecycleBean implements InitializingBean, DisposableBean,
        BeanNameAware, ApplicationContextAware {

    private static final Logger log = LoggerFactory.getLogger(LifecycleBean.class);
    private String beanName;
    private ApplicationContext context;

    // Phase 1: Constructor
    public LifecycleBean() {
        log.info("1. Constructor called");
    }

    // Phase 2: Aware interfaces
    @Override
    public void setBeanName(String name) {
        this.beanName = name;
        log.info("2a. setBeanName called: " + name);
    }

    @Override
    public void setApplicationContext(ApplicationContext ctx) {
        this.context = ctx;
        log.info("2b. setApplicationContext called");
    }

    // Phase 3: BeanPostProcessor pre-init (internal, happens before @PostConstruct)
    // Proxies created here

    // Phase 4a: @PostConstruct (called first)
    @PostConstruct
    public void init() {
        log.info("4a. @PostConstruct init() called");
    }

    // Phase 4b: InitializingBean (don't use both with @PostConstruct)
    @Override
    public void afterPropertiesSet() throws Exception {
        log.info("4b. InitializingBean.afterPropertiesSet() called");
    }

    // Phase 5: BeanPostProcessor post-init (internal)

    // Phase 6: Bean is ready
    public void doSomething() {
        log.info("6. Bean in use");
    }

    // Phase 7: Destruction (order: @PreDestroy, then DisposableBean, then destroy-method)
    @PreDestroy
    public void cleanup() {
        log.info("7a. @PreDestroy cleanup() called");
    }

    @Override
    public void destroy() throws Exception {
        log.info("7b. DisposableBean.destroy() called");
    }
}

// Custom BeanPostProcessor to observe lifecycle
@Component
public class LoggingBeanPostProcessor implements BeanPostProcessor {
    private static final Logger log = LoggerFactory.getLogger(LoggingBeanPostProcessor.class);

    @Override
    public Object postProcessBeforeInitialization(Object bean, String name) {
        if (bean instanceof LifecycleBean) {
            log.info("3. postProcessBeforeInitialization: " + name);
        }
        return bean;
    }

    @Override
    public Object postProcessAfterInitialization(Object bean, String name) {
        if (bean instanceof LifecycleBean) {
            log.info("5. postProcessAfterInitialization: " + name);
        }
        return bean;
    }
}

