// FALSE SHARING: Two threads, separate counters, same cache line
public class FalseSharingDemo {
    static class Counter {
        public long value = 0;  // might share cache line with next field
    }

    public static void main(String[] args) throws Exception {
        Counter counter1 = new Counter();
        Counter counter2 = new Counter();

        Thread t1 = new Thread(() -> {
            for (int i = 0; i < 100_000_000; i++) {
                counter1.value++;
            }
        });

        Thread t2 = new Thread(() -> {
            for (int i = 0; i < 100_000_000; i++) {
                counter2.value++;
            }
        });

        long start = System.nanoTime();
        t1.start();
        t2.start();
        t1.join();
        t2.join();
        long duration = System.nanoTime() - start;

        System.out.println("Duration: " + duration / 1_000_000 + "ms");
        // Output: ~2000-3000ms (slow due to false sharing)
    }
}

