    list.add(4);  // modifies list, but t1's iteration unaffected
});

t1.start();
t2.start();
t1.join();
t2.join();

// No ConcurrentModificationException

// PROBLEM: Frequent modifications
List<String> list = new CopyOnWriteArrayList<>();
for (int i = 0; i < 10000; i++) {
    list.add("item" + i);  // creates 10000 array copies (slow!)
}

// Better: use ArrayList with external sync or use a different structure
List<String> list = Collections.synchronizedList(new ArrayList<>());
for (int i = 0; i < 10000; i++) {
    list.add("item" + i);  // synchronized, no copies
}

// Or use ReadWriteLock for more control
ReadWriteLock lock = new ReentrantReadWriteLock();
List<String> list = new ArrayList<>();

lock.readLock().lock();
try {
    for (String item : list) { /* ... */ }
} finally {
    lock.readLock().unlock();
}

lock.writeLock().lock();
try {
    list.add("new");
} finally {
    lock.writeLock().unlock();
}

// CORRECT: @Transactional on service method
@Service
public class OrderService {
    @Autowired private OrderRepository orderRepo;
    @Autowired private PaymentService paymentService;

    @Transactional
    public void placeOrder(Order order) throws PaymentException {
        orderRepo.save(order);  // insert
        paymentService.charge(order.getTotal());  // external call
        // Both commit together or both rollback if payment fails
    }
}

