// PITFALL: Exception swallowed (no rollback)
@Service
public class ExceptionSwallow {
    @Transactional
    public void unsafeTransfer(Account from, Account to, BigDecimal amount) {
        from.debit(amount);
        try {
            to.credit(amount);
        } catch (Exception e) {
            log.error("Failed to credit", e);
            // Missing: rethrow exception
        }
        // Transaction commits even though credit failed
        // Money is debited but not credited (data loss)
    }
}

// FIXED: Rethrow or use rollbackFor
@Service
public class ExceptionFixed {
    @Transactional(rollbackFor = Exception.class)
    public void safeTransfer(Account from, Account to, BigDecimal amount) {
        from.debit(amount);
        try {
            to.credit(amount);
        } catch (Exception e) {
            log.error("Failed to credit", e);
            throw new TransferException("Credit failed", e);
        }
        // Transaction rolls back if credit fails
    }
}

