// CORRECT: Using interrupt() with proper cleanup
class SafeWorker extends Thread {
    @Override
    public void run() {
        try {
            while (!Thread.currentThread().isInterrupted()) {
                doWork();
                Thread.sleep(1000);  // might be interrupted here
            }
        } catch (InterruptedException e) {
            log.info("Worker interrupted, shutting down...");
            Thread.currentThread().interrupt();  // re-set flag
        } finally {
            cleanupResources();
        }
    }
}

// Usage
Worker worker = new SafeWorker();
worker.start();
Thread.sleep(5000);
worker.interrupt();  // signals thread to stop
worker.join();
// Thread shuts down gracefully, resources cleaned

// INCORRECT: Calling stop() (deprecated, never use)
Worker worker = new SafeWorker();
worker.start();
worker.stop();  // DANGEROUS: leaves thread in inconsistent state
// Resources may not be released, locks may be held

// CORRECT: ExecutorService (internally uses interrupt)
ExecutorService executor = Executors.newFixedThreadPool(4);
Future<?> future = executor.submit(() -> {
    try {
        while (!Thread.currentThread().isInterrupted()) {
            process();
            Thread.sleep(1000);
        }
    } catch (InterruptedException e) {
        Thread.currentThread().interrupt();
    }
});

// Interrupt the task
future.cancel(true);  // sends interrupt

// Shutdown executor (interrupts all workers)
executor.shutdownNow();
executor.awaitTermination(30, TimeUnit.SECONDS);

