// ForkJoinTask: sum an array recursively
class SumTask extends RecursiveTask<Long> {
    private static final int THRESHOLD = 1000;
    private int[] array;
    private int start, end;

    public SumTask(int[] array, int start, int end) {
        this.array = array;
        this.start = start;
        this.end = end;
    }

    @Override
    protected Long compute() {
        if (end - start <= THRESHOLD) {
            // Sequential computation for small array
            long sum = 0;
            for (int i = start; i < end; i++) {
                sum += array[i];
            }
            return sum;
        } else {
            // Divide and conquer
            int mid = (start + end) / 2;
            SumTask left = new SumTask(array, start, mid);
            SumTask right = new SumTask(array, mid, end);

            left.fork();  // submit to ForkJoinPool
            long rightResult = right.compute();  // compute in current thread
            long leftResult = left.join();  // wait for result

            return leftResult + rightResult;
        }
    }
}

// Usage
int[] array = new int[10_000_000];
ForkJoinPool pool = ForkJoinPool.commonPool();
long sum = pool.invoke(new SumTask(array, 0, array.length));

// Equivalent using parallel streams (internally uses ForkJoinPool)
long sum2 = Arrays.stream(array)
    .parallel()
    .mapToLong(x -> x)
    .sum();

// Work-stealing example
class TreeTask extends RecursiveTask<Integer> {
    private Node node;

    public TreeTask(Node node) {
        this.node = node;
    }

    @Override
    protected Integer compute() {
        if (node.isLeaf()) {
            return node.value;  // fast computation
        } else {
            TreeTask left = new TreeTask(node.left);
            TreeTask right = new TreeTask(node.right);

            left.fork();
            right.fork();  // both forked

            // If left's subtree is small, left thread finishes early
            // and steals tasks from right's queue
            return left.join() + right.join();
        }
    }
}

// Custom ForkJoinPool with specified parallelism
