// RecursiveAction (void return)
class PrintTask extends RecursiveAction {
    private int[] array;
    private int threshold;

    @Override
    protected void compute() {
        if (array.length <= threshold) {
            for (int x : array) System.out.println(x);
        } else {
            int mid = array.length / 2;
            PrintTask left = new PrintTask(Arrays.copyOfRange(array, 0, mid));
            PrintTask right = new PrintTask(Arrays.copyOfRange(array, mid, array.length));

            invokeAll(left, right);  // fork and join all
        }
    }
}
